(window.webpackJsonp=window.webpackJsonp||[]).push([[55],{365:function(t,o,e){"use strict";e.r(o);var r=e(5),n=Object(r.a)({},(function(){var t=this,o=t._self._c;return o("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[o("h1",{attrs:{id:"模型导出"}},[o("a",{staticClass:"header-anchor",attrs:{href:"#模型导出"}},[t._v("#")]),t._v(" 模型导出")]),t._v(" "),o("p",[t._v('当我们使用深度学习模型进行实际生产过程中的服务时，很多时候不会直接使用原始的模型文件（比如，PyTorch的pytorch_model.bin等需要通过load_state_dict加载的二进制文件），这是因为这些模型文件只能在python环境中运行，而且无法进行"优化"。举个例子，假如某个环境是嵌入式设备的单片机，那么在它的上面安装python环境是非常费力的；另外如果模型比较大，想要达到比较高的QPS，模型需要摆脱python环境而使用更快的C++库，或进行一些硬件相关的优化，或进行一些算子的融合。')]),t._v(" "),o("p",[t._v('在这种情况下，使用原始的代码和二进制文件运行就比较得不偿失，因此各类算法库都提供了对应的"导出格式"，比如PyTorch的TorchScript，TensorFlow的GraphDef，或者跨框架格式ONNX。这些格式不仅包含了模型的各类参数，也包含了模型动态图本身，因此可以脱离python环境独立运行并可以获得一定的运行加速，不少算子库也支持以这些格式为起点进行后续优化。ModelScope提供了其内模型的导出方法，用户可以自由选用。')]),t._v(" "),o("p",[t._v("ONNX 全称为开放神经网络交换格式（Open Neural Network Exchange），是微软和Facebook（Meta）联合提出用于表示深度学习模型的文件格式。 其特点为标准的文件格式，且具备平台无关性。也就是说，用户在任意框架（TensorFlow/PyTorch/JAX等）中训练得到的原始模型都可以转换为这种格式进行存储和优化，或转换为其他框架专用的模型文件。ONNX文件和其他输出格式一样，不仅存储了模型权重，也存储了模型DAG图以及一些有用的辅助信息。")])])}),[],!1,null,null,null);o.default=n.exports}}]);